@import './theme.css';
@import './utilities.css';

.react-aria-Calendar {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
  overflow: auto;
  width: 100%;
  max-width: fit-content;
  color: var(--text-color);
  font: var(--font-size) system-ui;

  .months {
    display: flex;
    gap: var(--spacing-3);
  }

  .month {
    width: calc(var(--spacing-9) * 7);
    min-width: calc(var(--spacing-7) * 7);
    container-type: inline-size;
  }

  header {
    display: flex;
    align-items: center;
    margin: 0 var(--spacing-1) var(--spacing-4) var(--spacing-1);
    min-height: var(--spacing-8);

    .react-aria-CalendarHeading {
      flex: 1;
      margin: 0;
      text-align: center;
      font-size: var(--font-size-lg);
    }
  }

  .react-aria-CalendarGrid {
    border-spacing: 0;
  }

  [slot='errorMessage'] {
    font: var(--font-size-sm) system-ui;
    color: var(--invalid-color);
  }
}

.react-aria-CalendarHeaderCell {
  font-size: var(--font-size-sm);
}

.react-aria-CalendarCell {
  --gap: var(--spacing-1);
  width: calc((100cqw / 7) - var(--gap));
  aspect-ratio: 1;
  margin: calc(var(--gap) / 2);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--font-size);
  text-align: center;
  border-radius: 9999px;
  cursor: default;
  forced-color-adjust: none;
  transition: scale 200ms;
  -webkit-tap-highlight-color: transparent;

  @media (min-resolution: 200dpi) {
    @container (width < 300px) {
      --gap: 0px;
    }
  }

  &[data-disabled] {
    opacity: 0.5;
  }

  &[data-pressed] {
    scale: 0.9;
  }

  &[data-unavailable] {
    text-decoration: line-through;
    color: var(--invalid-color);
  }

  &[data-invalid] {
    --button-color: var(--invalid-color);
  }
}

@import './theme.css';

.react-aria-Form {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-6);

  > .react-aria-Button {
    align-self: start;
  }
}

.react-aria-Form [role='alert'] {
  border: 2px solid var(--invalid-color);
  background: var(--overlay-background);
  border-radius: 6px;
  padding: 12px;
  max-width: 250px;
  outline: none;

  &:focus {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  h3 {
    margin-top: 0;
  }

  p {
    margin-bottom: 0;
  }
}

.react-aria-Label {
  display: block;
  font: var(--font-size) system-ui;
  color: var(--text-color);
  margin-bottom: var(--spacing-2);
  font-weight: 500;
}

.react-aria-FieldError {
  display: block;
  font: var(--font-size-sm) system-ui;
  color: var(--invalid-color);
  margin-top: var(--spacing-1);
  contain: inline-size;
}

.field-description {
  display: block;
  font: var(--font-size-sm) system-ui;
  margin-top: var(--spacing-1);
  contain: inline-size;

  [data-invalid] > & {
    display: none;
  }
}

.field-Button {
  background: var(--tint-200);
  color: var(--tint-1400);
  forced-color-adjust: none;
  border-radius: var(--radius-sm);
  border: none;
  margin-left: calc(-1 * var(--spacing-8) + 4px);
  height: calc(100% - 8px);
  aspect-ratio: 1/1;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  transition-property: scale, background;
  transition-duration: 200ms;
  -webkit-tap-highlight-color: transparent;

  svg {
    width: var(--spacing-4);
    height: var(--spacing-4);
  }

  &:where([data-hovered], [data-pressed]) {
    background: var(--tint-300);
    color: var(--tint-1200);
  }

  @media (forced-colors: active) {
    background: Highlight;
    color: HighlightText;
  }

  &[data-pressed] {
    scale: 0.9;
  }

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  &[data-disabled] {
    background: none;
    color: var(--text-color-disabled);
  }
}

@import './theme.css';
@import './utilities.css';

.react-aria-TagGroup {
  display: flex;
  flex-direction: column;
  font: var(--font-size) system-ui;
  color: var(--text-color);

  [slot='errorMessage'] {
    margin-top: var(--spacing);
    font-size: var(--font-size-sm);
    color: var(--invalid-color);
  }
}

.react-aria-TagList {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-2);
}

.react-aria-Tag {
  --button-color: var(--gray);
  --button-gradient-size: 4px;
  text-shadow: none;
  forced-color-adjust: none;
  border-radius: 9999px;
  height: var(--spacing-5);
  padding: 0 var(--spacing-3);
  font: var(--font-size-sm) system-ui;
  cursor: default;
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
  transition-property: scale, background, border-color, box-shadow, text-shadow;
  transition-duration: 200ms;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  -webkit-tap-highlight-color: transparent;

  &:has(.remove-button) {
    padding: 0 var(--spacing-1) 0 var(--spacing-2);
  }

  &[data-pressed] {
    scale: 0.96;
  }

  &[data-selected] {
    --button-color: var(--tint);
  }

  &[data-href] {
    text-decoration: none;
    cursor: pointer;
  }

  .remove-button {
    background: none;
    border: none;
    padding: 0;
    color: var(--gray-1000);
    transition: color 200ms;
    outline: none;
    border-radius: 100%;
    aspect-ratio: 1/1;
    height: calc(100% - 4px);
    display: flex;
    align-items: center;
    justify-content: center;
    transition-property: background, color, scale;
    transition-duration: 200ms;

    svg {
      width: calc(100% - 2px);
      height: calc(100% - 2px);
    }

    &:where([data-hovered], [data-pressed]) {
      background: var(--gray-300);
      color: var(--gray-1200);
    }

    @media (forced-colors: active) {
      background: ButtonFace;
      color: ButtonText;
    }

    &[data-pressed] {
      scale: 0.9;
    }

    &[data-focus-visible] {
      outline: 2px solid var(--focus-ring-color);
      outline-offset: -1px;
    }
  }

  &[data-selected] {
    .remove-button {
      color: inherit;
      &[data-hovered] {
        background: rgb(255 255 255 / 0.2);
      }
    }
  }
}

@import './theme.css';

.react-aria-ToastRegion {
  position: fixed;
  bottom: var(--spacing-4);
  right: var(--spacing-4);
  display: flex;
  flex-direction: column-reverse;
  gap: var(--spacing-2);
  border-radius: var(--radius-lg);
  outline: none;

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }
}

.react-aria-Toast {
  width: 230px;
  display: flex;
  align-items: center;
  gap: var(--spacing-4);
  background: var(--highlight-background);
  padding: var(--spacing-3) var(--spacing-4);
  border-radius: var(--radius-lg);
  outline: none;
  forced-color-adjust: none;
  view-transition-class: toast;

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  .react-aria-ToastContent {
    display: flex;
    flex-direction: column;
    flex: 1 1 auto;
    min-width: 0;
    font: var(--font-size) system-ui;

    [slot='title'] {
      font-weight: 600;
      color: var(--highlight-foreground);
    }

    [slot='description'] {
      font-size: var(--font-size-sm);
      color: var(--highlight-foreground);
    }
  }

  .react-aria-Button[slot='close'] {
    flex: 0 0 auto;
    background: none;
    border: none;
    appearance: none;
    border-radius: var(--radius-sm);
    height: var(--spacing-8);
    width: var(--spacing-8);
    color: var(--highlight-foreground);
    padding: 0;
    outline: none;
    -webkit-tap-highlight-color: transparent;

    &[data-hovered] {
      background: var(--tint-900);
      box-shadow: none;
    }

    &[data-focus-visible] {
      outline: 2px solid var(--highlight-foreground);
      outline-offset: 2px;
    }

    &[data-pressed] {
      background: var(--highlight-pressed);
      box-shadow: none;
    }
  }
}

::view-transition-new(.toast):only-child {
  animation: slide-in 400ms;
}

::view-transition-old(.toast):only-child {
  animation: slide-out 400ms;
  animation-fill-mode: forwards;
}

@keyframes slide-out {
  to {
    translate: 100% 0;
    opacity: 0;
    visibility: hidden;
  }
}

@keyframes slide-in {
  from {
    translate: 100% 0;
    opacity: 0;
  }
}

@layer components {
  .Text {
    box-sizing: border-box;
    font-family:
      'die grotesk a',
      system-ui,
      -apple-system,
      BlinkMacSystemFont,
      'Helvetica Neue',
      arial,
      sans-serif;
    margin: 0;
    font-weight: var(--font-weight-400);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    text-wrap: pretty;
  }

  .Text.sz-1 {
    font-size: 15px;
    line-height: 22px;
  }

  .Text.sz-2 {
    font-size: 18px;
    line-height: 25px;
  }

  .Text.sz-3 {
    font-size: var(--font-size-34);
    line-height: 34px;
    text-wrap: balance;
    font-family:
      'die grotesk b',
      system-ui,
      -apple-system,
      BlinkMacSystemFont,
      'Helvetica Neue',
      arial,
      sans-serif;
  }

  .Text.sz-4 {
    font-size: 42px;
    line-height: 44px;
    text-wrap: balance;
    font-family:
      'die grotesk b',
      system-ui,
      -apple-system,
      BlinkMacSystemFont,
      'Helvetica Neue',
      arial,
      sans-serif;
  }

  @media (min-width: 48rem) {
    .Text.bp2\:sz-1 {
      font-size: 15px;
      line-height: 22px;
    }

    .Text.bp2\:sz-2 {
      font-size: 18px;
      line-height: 25px;
    }

    .Text.bp2\:sz-3 {
      font-size: var(--font-size-34);
      line-height: 34px;
      text-wrap: balance;
      font-family:
        'die grotesk b',
        system-ui,
        -apple-system,
        BlinkMacSystemFont,
        'Helvetica Neue',
        arial,
        sans-serif;
    }

    .Text.bp2\:sz-4 {
      font-size: 42px;
      line-height: 44px;
      text-wrap: balance;
      font-family:
        'die grotesk b',
        system-ui,
        -apple-system,
        BlinkMacSystemFont,
        'Helvetica Neue',
        arial,
        sans-serif;
    }
  }
}

@import 'docs/src/css/custom-media.css';

@layer components {
  .DescriptionList {
    width: 100%;
    display: grid;
    grid-template-columns: auto 1fr;
    row-gap: var(--space-12);
  }

  .DescriptionListItem {
    position: relative;

    @media (--xs) {
      display: grid;
      grid-template-columns: subgrid;
      grid-column: span 3;
      align-items: start;
    }
  }

  .DescriptionTerm {
    font-size: var(--font-size-14);
    line-height: 1.25rem;
    font-weight: var(--font-weight-700);
    color: var(--color-foreground);
    white-space: nowrap;
    word-break: keep-all;
    position: relative;
    display: flex;
    align-items: center;
    margin-bottom: var(--space-4);

    @media (--xs) {
      font-weight: revert-layer;
      color: revert-layer;
      margin-bottom: 0;
    }

    &.separator {
      &::before {
        content: '';
        box-shadow: inset 0 1px 0 0 var(--gray-c2);
        position: absolute;
        top: 0;
        inset-inline: 0.75rem 1rem;
        height: 1px;
      }

      @media (--xs) {
        &::before {
          height: 0;
        }
      }
    }
  }

  .DescriptionListDetails {
    font-size: var(--font-size-14);
    line-height: 1.25rem;

    color: var(--color-foreground);
    grid-column: span 2;

    & p {
      margin: 0 !important;
    }
  }

  .DescriptionListInner {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: start;
    padding-inline: 0.75rem;
    width: 100%;
    gap: var(--space-12);

    .CodeBlockRoot {
      margin: 0;
      max-width: 100%;
    }

    & > p:last-of-type {
      margin-bottom: 0;
    }

    .separator & {
      padding-top: var(--space-8);
    }

    @media (--xs) {
      min-height: 2.5rem;

      &,
      .separator & {
        padding: 0.625rem 0.75rem;
      }
    }
  }
}

@layer utilities {
